local function validate_token()
    local auth_header = ngx.var.http_authorization
    if not auth_header then
        return nil, "Missing authorization header"
    end
    
    local token = string.match(auth_header, "Bearer%s+(.+)")
    if not token then
        return nil, "Invalid token format"
    end
    
    -- Simulate token validation (replace with actual JWT validation or DB lookup)
    local decoded_token = ngx.decode_base64(token)
    if not decoded_token then
        return nil, "Invalid token encoding"
    end
    
    local user_data = cjson.decode(decoded_token)
    if not user_data or not user_data.user_id or not user_data.role then
        return nil, "Invalid token data"
    end
    
    return user_data.user_id, user_data.role
end

local function check_permission(required_role)
    local user_id, user_role = validate_token()
    if not user_id then
        return false, "Authentication failed"
    end
    
    -- Role hierarchy check (admin > manager > user)
    local role_hierarchy = {
        admin = 3,
        manager = 2,
        user = 1
    }
    
    if not role_hierarchy[user_role] or not role_hierarchy[required_role] then
        return false, "Invalid role"
    end
    
    if role_hierarchy[user_role] >= role_hierarchy[required_role] then
        return true
    else
        return false, "Insufficient permissions"
    end
end

local function should_skip_check()
    local uri = ngx.var.uri or ""
    return string.find(uri, "/admin", 1, true) or string.find(uri, "/api", 1, true)
end

if should_skip_check() then
    return
end

local required_role = "user"
local path = ngx.var.uri or ""

if string.find(path, "/admin/users", 1, true) then
    required_role = "admin"
elseif string.find(path, "/admin/settings", 1, true) then
    required_role = "manager"
end

local allowed, error_msg = check_permission(required_role)
if not allowed then
    ngx.status = 403
    ngx.say(cjson.encode({error = error_msg}))
    ngx.exit(403)
end